    75→            // partition based on uniform distribution.
    76→            List<PartitionInfo> availablePartitions = cluster.availablePartitionsForTopic(topic);
    77→            if (!availablePartitions.isEmpty()) {
    78→                partition = availablePartitions.get(random % availablePartitions.size()).partition();
    79→            } else {
