    85→            // Calculate next partition based on load distribution.
    86→            // Note that partitions without leader are excluded from the partitionLoadStats.
    87→            assert partitionLoadStats.length > 0;
    88→
    89→            int[] cumulativeFrequencyTable = partitionLoadStats.cumulativeFrequencyTable;
    90→            int weightedRandom = random % cumulativeFrequencyTable[partitionLoadStats.length - 1];
    91→
    92→            // By construction, the cumulative frequency table is sorted, so we can use binary
    93→            // search to find the desired index.
    94→            int searchResult = Arrays.binarySearch(cumulativeFrequencyTable, 0, partitionLoadStats.length, weightedRandom);
